module top_module(clk,we,waddr,raddr,wdata,rdata);input clk;				
  input we;					
  input [9:0] waddr;		
  input [9:0] raddr;		
  input [15:0] wdata;		
  output reg [15:0] rdata;	


  reg [15:0] obf_mem [1023:0];

  always @(posedge clk) begin
    if (we)
      obf_mem[waddr] <= wdata;
    rdata <= obf_mem[raddr];
  end


endmodule
